-- ============================================================================
-- Quiz Seed: 1 Chronicles — Part 2 (Chapters 11–20)
-- 3 difficulties × 10 chapters = 160 total questions
-- kids: 3 Qs, teens: 5 Qs, adults: 8 Qs per chapter
-- correct_answer is always 'a'
-- ============================================================================

-- ═══ 1 Chronicles Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 11, 'kids', 1, 'What city did David capture to make his royal home?', 'Jerusalem, also called Zion', 'Hebron', 'Bethlehem', 'Jericho', 'a', '1 Chronicles 11:5 — "David took the castle of Zion, which is the city of David."'),
('1 Chronicles', 11, 'kids', 2, 'Who was the first and mightiest of David''s thirty mighty men?', 'Jashobeam, a Hachmonite', 'Joab the son of Zeruiah', 'Eleazar the son of Dodo', 'Abishai the brother of Joab', 'a', '1 Chronicles 11:11 — "Jashobeam, an Hachmonite, the chief of the captains: he lifted up his spear against three hundred slain by him at one time."'),
('1 Chronicles', 11, 'kids', 3, 'What did David''s three mighty men bring him from Bethlehem at great risk?', 'Water from the well of Bethlehem', 'Bread from the city gate', 'A sword from Goliath''s tomb', 'Gold from the treasury', 'a', '1 Chronicles 11:18 — "The three brake through the host of the Philistines, and drew water out of the well of Bethlehem...and brought it to David."'),
-- Teens
('1 Chronicles', 11, 'teens', 1, 'What agreement did all Israel make with David at Hebron before crowning him king?', 'They said he was their bone and flesh and made a league with him before the LORD', 'They demanded he free all prisoners first', 'They asked him to swear not to appoint foreigners as officers', 'They required him to bring the ark to Jerusalem first', 'a', '1 Chronicles 11:1,3 — "All Israel gathered themselves to David unto Hebron, saying, Behold, we are thy bone and thy flesh...they anointed David king over Israel."'),
('1 Chronicles', 11, 'teens', 2, 'Who was the commander of the Jebusites when David attacked Jerusalem, and what did he say?', 'The Jebusites said even the blind and the lame could defend the city', 'The commander Araunah offered to surrender peacefully', 'The Jebusite king Adoni-zedek fled before David''s army', 'The Jebusites sent Ornan to negotiate a ransom', 'a', '1 Chronicles 11:5 — "The inhabitants of Jebus said to David, Thou shalt not come hither." David nonetheless took the castle of Zion.'),
('1 Chronicles', 11, 'teens', 3, 'What reward did David promise to whoever first attacked the Jebusites of Jerusalem?', 'He would be chief and captain', 'He would receive half the kingdom', 'He would be given the city as his inheritance', 'He would marry David''s daughter', 'a', '1 Chronicles 11:6 — "Whosoever smiteth the Jebusites first shall be chief and captain. So Joab the son of Zeruiah went first up, and was chief."'),
('1 Chronicles', 11, 'teens', 4, 'What mighty deed did Eleazar perform at Pas-dammim that made him famous?', 'He stood his ground and smote the Philistines until his hand clave to his sword', 'He killed thirty Philistines with a donkey''s jawbone', 'He slew a lion in a pit on a snowy day', 'He shot down the Philistine champion with a sling', 'a', '1 Chronicles 11:13-14 — Eleazar and David "set themselves in the midst of that parcel...and slew the Philistines; and the LORD saved them by a great deliverance."'),
('1 Chronicles', 11, 'teens', 5, 'Why did David refuse to drink the water his mighty men brought from Bethlehem?', 'Because it was as the blood of men who had risked their lives to get it', 'Because he had vowed to fast until the Philistines were defeated', 'Because the water was unclean from the enemy camp', 'Because it was a Sabbath and he would not eat until sundown', 'a', '1 Chronicles 11:19 — "David said, My God forbid it me, that I should do this thing: shall I drink the blood of these men that have put their lives in jeopardy?"'),
-- Adults
('1 Chronicles', 11, 'adults', 1, 'What theological explanation does the Chronicler give for David''s conquest of Jerusalem?', 'The LORD of hosts was with David and he went on and grew great', 'David used clever military strategy to scale the walls', 'The Jebusites weakened themselves through internal strife', 'God sent an angel to strike fear into the Jebusite garrison', 'a', '1 Chronicles 11:9 — "David waxed greater and greater: for the LORD of hosts was with him."'),
('1 Chronicles', 11, 'adults', 2, 'What was Joab''s role in the restoration of Jerusalem after David captured it?', 'Joab repaired the rest of the city', 'Joab built the temple foundation', 'Joab organized the Levites for worship', 'Joab catalogued all the treasures of the Jebusites', 'a', '1 Chronicles 11:8 — "David built the city round about...and Joab repaired the rest of the city."'),
('1 Chronicles', 11, 'adults', 3, 'What heroic exploit is attributed to Abishai the brother of Joab, and what rank did it earn him?', 'He lifted up his spear against three hundred and slain them, earning him the name of the three', 'He killed Goliath''s brother in single combat and became chief captain', 'He defended the breach alone when the Philistines nearly broke through', 'He rescued David from Ishbi-benob the giant and was made a general', 'a', '1 Chronicles 11:20 — "Abishai the brother of Joab, he was chief of the three: for lifting up his spear against three hundred, he slew them, and had a name among the three."'),
('1 Chronicles', 11, 'adults', 4, 'What distinction does the text make between Benaiah son of Jehoiada and the three mighty men?', 'He was more honourable than the thirty but attained not to the first three, and David set him over his guard', 'He surpassed the three in battle but refused the honour', 'He was equal to the three in rank but served a different king', 'He was chief over the Levites rather than the warriors', 'a', '1 Chronicles 11:25 — "Behold, he was honourable among the thirty, but attained not to the first three: and David set him over his guard."'),
('1 Chronicles', 11, 'adults', 5, 'What three feats are listed for Benaiah son of Jehoiada in chapter 11?', 'He slew two lion-like men of Moab, slew a lion in a pit in snowy weather, and slew an Egyptian giant', 'He killed the Philistine giant Goliath''s son, slew a bear, and defeated thirty men alone', 'He won three single combats, was never wounded in battle, and served David forty years', 'He fought a lion, killed a giant, and defended the threshing floor alone', 'a', '1 Chronicles 11:22-23 — "He slew two lionlike men of Moab: he went down also and slew a lion in a pit in a snowy day. And he slew an Egyptian, a man of great stature, five cubits high."'),
('1 Chronicles', 11, 'adults', 6, 'How does the Chronicler''s account of David becoming king differ from 2 Samuel by what it omits?', 'Chronicles omits all of David''s struggles with Saul''s house, presenting an immediate united coronation', 'Chronicles omits the capture of Jerusalem entirely', 'Chronicles omits the list of mighty men found in 2 Samuel', 'Chronicles records David becoming king of all Israel before capturing Jerusalem', 'a', '1 Chronicles 11:1-3 — The Chronicler skips the seven-year period in Hebron as king of Judah only (2 Samuel 2-4), presenting all Israel uniting with David immediately, emphasising unity and divine purpose.'),
('1 Chronicles', 11, 'adults', 7, 'What does it mean that Samuel''s word was fulfilled when David became king over all Israel?', 'The LORD''s word by Samuel that David would shepherd and rule Israel was now accomplished', 'Samuel had predicted exactly how many warriors would come to Hebron', 'The book of Samuel declared that Jerusalem must be the capital', 'A prophecy from Samuel stated that Israel would be united under one king within twenty years', 'a', '1 Chronicles 11:3 — "According to the word of the LORD by Samuel" — this phrase anchors David''s coronation in prophetic fulfilment, showing the Chronicler''s theological emphasis on God''s Word being accomplished.'),
('1 Chronicles', 11, 'adults', 8, 'The Chronicler lists thirty-seven mighty men in total. What does this catalogue serve to demonstrate theologically?', 'That David''s kingdom was built on loyal, Spirit-empowered human instruments whom God gathered to him', 'That David''s military power made him the greatest king in the ancient Near East', 'That the tribe of Judah produced more warriors than all other tribes combined', 'That Israel''s army was larger than Egypt''s at this time', 'a', '1 Chronicles 11:10 — "These also are the chief of the mighty men whom David had, who strengthened themselves with him in his kingdom...to make him king, according to the word of the LORD."');

-- ═══ 1 Chronicles Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 12, 'kids', 1, 'The warriors who came to David at Ziklag could shoot arrows and sling stones with which hand?', 'Either the right hand or the left', 'Only the right hand', 'Only the left hand', 'Their stronger hand only', 'a', '1 Chronicles 12:2 — "They were armed with bows, and could use both the right hand and the left in hurling stones and shooting arrows out of a bow."'),
('1 Chronicles', 12, 'kids', 2, 'What tribe did the fierce warriors come from who had faces like lions and were swift as roes?', 'The tribe of Gad', 'The tribe of Dan', 'The tribe of Asher', 'The tribe of Naphtali', 'a', '1 Chronicles 12:8 — "And of the Gadites there separated themselves unto David...whose faces were like the faces of lions, and were as swift as the roes upon the mountains."'),
('1 Chronicles', 12, 'kids', 3, 'What did the people who came to David at Hebron do for three days?', 'They ate and drank, feasting and celebrating with David', 'They built new houses for David''s army', 'They trained with their weapons in the fields', 'They offered sacrifices and prayed for three days', 'a', '1 Chronicles 12:39 — "There they were with David three days, eating and drinking: for their brethren had prepared for them."'),
-- Teens
('1 Chronicles', 12, 'teens', 1, 'Why did some of the men of Benjamin and Judah come to David when he was at Ziklag hiding from Saul?', 'They came to help him, and David said if they came peaceably to help him his heart would be knit to them', 'They came to spy on him for King Saul', 'They came to demand tribute from David before joining him', 'They came to warn David of Saul''s approaching army', 'a', '1 Chronicles 12:17 — David said, "If ye be come peaceably unto me to help me, mine heart shall be knit unto you: but if ye be come to betray me to mine enemies, seeing there is no wrong in mine hands, the God of our fathers look thereon."'),
('1 Chronicles', 12, 'teens', 2, 'What happened when the Spirit came upon Amasai, chief of the captains?', 'He declared, "Thine are we, David, and on thy side, thou son of Jesse"', 'He prophesied that David would defeat the Philistines', 'He fell prostrate before David and wept', 'He called all the warriors of Benjamin to come to Hebron', 'a', '1 Chronicles 12:18 — "Then the spirit came upon Amasai, who was chief of the captains, and he said, Thine are we, David, and on thy side, thou son of Jesse: peace, peace be unto thee."'),
('1 Chronicles', 12, 'teens', 3, 'What do the men of Issachar contribute that sets them apart from the other warriors listed?', 'They had understanding of the times to know what Israel ought to do', 'They brought the most soldiers of any tribe', 'They supplied the army with food and provisions', 'They were skilled in using chariots in battle', 'a', '1 Chronicles 12:32 — "And of the children of Issachar, which were men that had understanding of the times, to know what Israel ought to do; the heads of them were two hundred."'),
('1 Chronicles', 12, 'teens', 4, 'How large was the army that came to Hebron to make David king, as described in verse 22?', 'Like the host of God — a great host', 'Three hundred thousand strong', 'Larger than the army of Egypt', 'Equal to the stars of heaven in number', 'a', '1 Chronicles 12:22 — "For at that time day by day there came to David to help him, until it was a great host, like the host of God."'),
('1 Chronicles', 12, 'teens', 5, 'Which distant tribe sent six hundred men armed with all weapons of war and with a perfect heart?', 'The tribe of Asher, who kept rank', 'The tribe of Dan with 28,600 men', 'The tribe of Zebulun with 50,000 men', 'The Gadites who crossed the Jordan', 'a', '1 Chronicles 12:33 — "Of Zebulun, such as went forth to battle, expert in war, with all instruments of war, fifty thousand, which could keep rank: they were not of double heart." (Asher in v.36 sent 40,000 keeping rank with a perfect heart.)'),
-- Adults
('1 Chronicles', 12, 'adults', 1, 'During the conflict between David and Saul, some Manassites deserted to David before the battle of Jezreel. What does the text say they helped with?', 'They fell to David as he went to battle with the Philistines against Saul', 'They led David''s cavalry in the attack on Gibeah', 'They brought intelligence about Saul''s troop movements', 'They killed Saul''s charioteers at the pass of Megiddo', 'a', '1 Chronicles 12:19 — "There fell some of Manasseh to David, when he came with the Philistines against Saul to battle."'),
('1 Chronicles', 12, 'adults', 2, 'What concern did the Philistine lords express that caused them to send David away before the battle?', 'They feared David might reconcile with Saul against them in battle', 'They were worried David''s men were outnumbered', 'They did not want a foreigner commanding their rear guard', 'They suspected David was secretly loyal to the tribe of Judah', 'a', '1 Chronicles 12:19 — The Philistine lords said David "fell to Saul his master" — the parallel passage in 1 Samuel 29:4 shows their fear that David might turn against them.'),
('1 Chronicles', 12, 'adults', 3, 'How many Gadite warriors are described crossing the Jordan in the first month when it overflowed its banks?', 'They put to flight all them of the valleys, both toward the east and toward the west', 'Eleven chief men crossed with a thousand behind each', 'Seven hundred crossed in the night season', 'Four thousand horsemen forded the swollen river', 'a', '1 Chronicles 12:15 — "These are they that went over Jordan in the first month, when it had overflown all his banks; and they put to flight all them of the valleys, both toward the east, and toward the west."'),
('1 Chronicles', 12, 'adults', 4, 'What staggering total does the text give for the tribe of Zebulun at Hebron, and how are they described?', 'Fifty thousand expert in war with all instruments of war, keeping rank, not of double heart', 'One hundred thousand cavalry and infantry combined', 'Thirty thousand captains with their divisions', 'Seventy thousand who had taken an oath of loyalty to David', 'a', '1 Chronicles 12:33 — "Of Zebulun, such as went forth to battle, expert in war, with all instruments of war, fifty thousand, which could keep rank: they were not of double heart."'),
('1 Chronicles', 12, 'adults', 5, 'Which two tribes sent their contingents with bread, meal, cakes of figs, bunches of raisins, wine, oil, and oxen and sheep in abundance?', 'Those who were nigh them even unto Issachar and Zebulun and Naphtali brought food', 'Judah and Simeon supplied all the food for the festival', 'Ephraim and Manasseh brought provisions from across the Jordan', 'Benjamin and Gad organized the supply lines to Hebron', 'a', '1 Chronicles 12:40 — "Moreover they that were nigh them, even unto Issachar and Zebulun and Naphtali, brought bread on asses, and on camels, and on mules, and on oxen...for there was joy in Israel."'),
('1 Chronicles', 12, 'adults', 6, 'What is the theological significance of the phrase "with a perfect heart" used to describe the warriors'' allegiance to David?', 'It indicates wholehearted, undivided covenant loyalty — a quality the Chronicler consistently values as prerequisite for God''s blessing', 'It means the warriors had passed a physical fitness test showing no disease or defect', 'It refers to a legal oath sworn before the high priest at the ark', 'It indicates all warriors had been circumcised and were ritually clean before coming', 'a', '1 Chronicles 12:38 — "All these men of war, that could keep rank, came with a perfect heart to Hebron, to make David king over all Israel." The Chronicler uses "perfect heart" (shalem lev) as a key theological marker throughout Chronicles.'),
('1 Chronicles', 12, 'adults', 7, 'How do the numbers in chapter 12 function rhetorically and theologically in the Chronicler''s narrative?', 'They present a panoramic vision of all twelve tribes uniting under God''s chosen king, showing the ideal of Israel as one worshipping community', 'They are intended as a precise military census matching the numbers in Numbers', 'They are symbolic round numbers with no relationship to historical reality', 'They demonstrate that the northern tribes were militarily superior to Judah', 'a', '1 Chronicles 12:38 — The Chronicler''s enormous totals (e.g., Judah 6,800; Zebulun 50,000) create a portrait of all-Israel unity under David — a central theological concern of Chronicles — mirroring the ideal Mosaic assembly.'),
('1 Chronicles', 12, 'adults', 8, 'What does the joy at Hebron at the end of chapter 12 prefigure or anticipate in the broader Chronicler narrative?', 'The joyful worship at Jerusalem when the ark is brought and when the temple is dedicated — joy is the hallmark of right worship in Chronicles', 'The victory celebration after David defeats Goliath', 'The feast of Tabernacles that Solomon will institute at the temple dedication', 'The return of the exiles from Babylon described in Ezra-Nehemiah', 'a', '1 Chronicles 12:40 — "There was joy in Israel." The Chronicler consistently uses joy as a theological signal of covenant faithfulness; this foreshadows the great joy at the ark''s return (ch. 15-16) and the temple dedication (2 Chronicles 7).');

-- ═══ 1 Chronicles Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 13, 'kids', 1, 'What did David want to bring back to Jerusalem?', 'The ark of God', 'The tabernacle of Moses', 'The golden lampstand', 'The bronze altar', 'a', '1 Chronicles 13:3 — "Let us bring again the ark of our God to us: for we enquired not at it in the days of Saul."'),
('1 Chronicles', 13, 'kids', 2, 'What happened to Uzza when he touched the ark?', 'God struck him dead', 'He was blinded for a week', 'He fell into a deep sleep', 'He was made lame in his feet', 'a', '1 Chronicles 13:10 — "And the anger of the LORD was kindled against Uzza, and he smote him, because he put his hand to the ark: and there he died before God."'),
('1 Chronicles', 13, 'kids', 3, 'Where was the ark kept after Uzza died and David was afraid to bring it to Jerusalem?', 'In the house of Obed-edom the Gittite', 'In the tent at Gibeon', 'In the house of Abinadab at Kirjath-jearim', 'In the tabernacle of Moses', 'a', '1 Chronicles 13:13-14 — "David carried it not home to himself to the city of David, but carried it aside into the house of Obed-edom the Gittite."'),
-- Teens
('1 Chronicles', 13, 'teens', 1, 'From what place did David and Israel go to fetch the ark at the beginning of chapter 13?', 'Kirjath-jearim, also called Baalah of Judah', 'Shiloh, where the tabernacle had stood', 'Gibeah, from the house of Abinadab', 'Bethlehem, the city of David''s birth', 'a', '1 Chronicles 13:6 — "David went up, and all Israel, to Baalah, that is, to Kirjath-jearim, which belonged to Judah."'),
('1 Chronicles', 13, 'teens', 2, 'How did they transport the ark from Kirjath-jearim, and why was this later shown to be wrong?', 'On a new cart, but it should have been carried by Levites on their shoulders with poles', 'On the shoulders of priests wearing linen ephods, which was correct', 'In a covered wagon drawn by oxen, as Moses had commanded for heavy items', 'By hand on a litter of acacia wood, which was the approved method', 'a', '1 Chronicles 13:7 — "They carried the ark of God in a new cart." This violated Numbers 7:9 which required the Kohathites to carry it on their shoulders; David later acknowledges this in 1 Chronicles 15:13.'),
('1 Chronicles', 13, 'teens', 3, 'Why did Uzza put his hand on the ark, and what does the text call the act that led to his death?', 'The oxen stumbled and Uzza held the ark steady, which was called the breach of Uzza', 'Uzza deliberately touched the ark as a sign of reverence', 'An enemy soldier tried to seize the ark and Uzza defended it', 'Uzza was ordered by David to steady the ark on the steep path', 'a', '1 Chronicles 13:9-11 — "The oxen stumbled. And Uzza put forth his hand to hold the ark...and God smote him...and that place is called Perez-uzza to this day."'),
('1 Chronicles', 13, 'teens', 4, 'What two emotions did David feel after Uzza died, and what did he do as a result?', 'He was both displeased and afraid, so he did not take the ark home but left it at Obed-edom''s house', 'He was grieved and angry, so he ordered a fast throughout Israel', 'He was humbled and repentant, so he built an altar on the spot', 'He was confused and determined, so he consulted the prophets about the right procedure', 'a', '1 Chronicles 13:11-13 — "David was displeased...and David was afraid of God that day...So David brought not the ark home to himself to the city of David, but carried it aside into the house of Obed-edom."'),
('1 Chronicles', 13, 'teens', 5, 'How long did the ark remain at the house of Obed-edom, and what effect did it have there?', 'Three months; the LORD blessed Obed-edom and all his household', 'Seven months; God sent rain on his fields every week', 'One year; all his enemies were defeated while the ark was there', 'Forty days; the household grew and multiplied greatly', 'a', '1 Chronicles 13:14 — "The ark of God remained with the family of Obed-edom in his house three months. And the LORD blessed the house of Obed-edom, and all that he had."'),
-- Adults
('1 Chronicles', 13, 'adults', 1, 'With whom did David consult before deciding to bring back the ark, and what does this reveal about his leadership?', 'He consulted all the congregation of Israel — from Shihor of Egypt to Hamath — showing broad participatory leadership', 'He consulted only the high priest Zadok and prophet Nathan', 'He asked the elders of Judah alone as the leading tribe', 'He sought counsel only from his mighty men who were present', 'a', '1 Chronicles 13:1-4 — "David consulted with the captains of thousands and hundreds...And David said unto all the congregation of Israel..." The Chronicler emphasises that the whole congregation agreed, establishing ark-retrieval as a corporate act.'),
('1 Chronicles', 13, 'adults', 2, 'What does David''s statement that "we enquired not at it in the days of Saul" reveal about his theological diagnosis of Saul''s reign?', 'That Saul''s failure to seek God through the ark was the root cause of his reign''s spiritual poverty and eventual collapse', 'That the ark had been lost during Saul''s reign and must be found', 'That Saul had deliberately hidden the ark to consolidate his own power', 'That Saul had been excommunicated from the congregation and denied ark access', 'a', '1 Chronicles 13:3 — "Let us bring again the ark of our God to us: for we enquired not at it in the days of Saul." This contrast sets up a major Chronicler theme: seeking God versus not seeking God determines national destiny.'),
('1 Chronicles', 13, 'adults', 3, 'What is the full title given to the ark in verse 6 that reveals its theological significance?', 'The ark of God the LORD, that dwelleth between the cherubims, whose name is called on it', 'The ark of the covenant of the LORD of hosts', 'The ark of the testimony of the Most High God', 'The ark of Moses and the tabernacle of the congregation', 'a', '1 Chronicles 13:6 — "The ark of God the LORD, that dwelleth between the cherubims, whose name is called on it."'),
('1 Chronicles', 13, 'adults', 4, 'What does the name "Perez-uzza" mean, and how does naming function in this narrative?', 'It means "breach of Uzza" — naming memorialises the event and signals divine judgment even on well-intentioned violation of the sacred', 'It means "the wrath of God" in Hebrew and warns all future ark-carriers', 'It means "the place of stumbling" and marks where the oxen fell', 'It means "the death of the righteous" as a memorial of Uzza''s piety', 'a', '1 Chronicles 13:11 — "Wherefore that place is called Perez-uzza to this day." In Hebrew, Perez-uzza means "breach/outburst against Uzza," preserving the memory of divine holiness.'),
('1 Chronicles', 13, 'adults', 5, 'What Mosaic regulation had been violated in the transport of the ark on a cart, which David later acknowledges?', 'Only the Levites of the Kohathite family were permitted to carry the ark on their shoulders using poles — carts were forbidden', 'The ark was supposed to be wrapped in three layers of cloth before transport', 'The ark could only be moved at night after priestly purification ceremonies', 'Only the high priest could direct the movement of the ark during transport', 'a', '1 Chronicles 15:13 — David later explains: "For because ye did it not at the first, the LORD our God made a breach upon us, for that we sought him not after the due order." Numbers 4:15 and 7:9 specify Kohathite shoulder-carrying.'),
('1 Chronicles', 13, 'adults', 6, 'How does the Chronicler''s version of the ark narrative differ from 2 Samuel 6 in its emphasis?', 'Chronicles includes the broad all-Israel consultation (vv.1-4) that 2 Samuel omits, stressing corporate worship and national unity', 'Chronicles records Michal''s contempt for David while 2 Samuel omits it', 'Chronicles names the threshing floor differently than 2 Samuel 6', 'Chronicles records Uzza''s death before the cart journey began', 'a', '1 Chronicles 13:1-4 is unique to Chronicles — the extended consultation with all Israel is not in 2 Samuel 6, reflecting the Chronicler''s characteristic emphasis on the whole assembly in worship.'),
('1 Chronicles', 13, 'adults', 7, 'What does God''s blessing of Obed-edom''s household for three months communicate about the nature of the ark''s presence?', 'That the ark''s holiness is not merely dangerous but also profoundly life-giving to those who receive it rightly', 'That Obed-edom was a more righteous man than David', 'That the ark''s blessings were only for Gentiles who welcomed it', 'That the three months represented a period of ceremonial cleansing before David could receive it', 'a', '1 Chronicles 13:14 — "The LORD blessed the house of Obed-edom, and all that he had." The ark is both consuming fire (Uzza) and life-giving blessing (Obed-edom) — God''s holiness is a two-edged reality.'),
('1 Chronicles', 13, 'adults', 8, 'What theological principle about approaching God does the Perez-uzza incident establish for the entire Books of Chronicles?', 'That God must be approached "after the due order" — His holiness demands prescribed means, not sincere improvisation', 'That the ark is too dangerous for human hands and should remain in a fixed location', 'That only Levites and priests are ever safe in God''s presence', 'That God punishes all mistakes instantly, without allowance for ignorance', 'a', '1 Chronicles 15:13 — "For because ye did it not at the first, the LORD our God made a breach upon us, for that we sought him not after the due order." Good intentions cannot substitute for obedience to God''s prescribed means of approach.');

-- ═══ 1 Chronicles Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 14, 'kids', 1, 'Which foreign king sent workers and cedar wood to help David build a palace?', 'Hiram king of Tyre', 'Pharaoh king of Egypt', 'Achish king of Gath', 'Hadarezer king of Syria', 'a', '1 Chronicles 14:1 — "Hiram king of Tyre sent messengers to David, and timber of cedars, with masons and carpenters, to build him an house."'),
('1 Chronicles', 14, 'kids', 2, 'Before fighting the Philistines the second time, what did God tell David to listen for in the mulberry trees?', 'The sound of going in the tops of the mulberry trees', 'An angel''s voice calling his name', 'Thunder and lightning from the sky', 'The sound of trumpets in the camp', 'a', '1 Chronicles 14:15 — "When thou shalt hear a sound of going in the tops of the mulberry trees, then thou shalt go out to battle."'),
('1 Chronicles', 14, 'kids', 3, 'What happened to the Philistines'' gods after David''s first victory over them?', 'David commanded they be burned with fire', 'David carried them back to Jerusalem as trophies', 'David melted them into silver and gold', 'David threw them into the sea', 'a', '1 Chronicles 14:12 — "They had left their gods there; and David gave a commandment, and they were burned with fire."'),
-- Teens
('1 Chronicles', 14, 'teens', 1, 'What sign did David recognise that the LORD had confirmed him as king over Israel?', 'His kingdom was lifted up on high because of his people Israel', 'The ark was safely housed in Jerusalem', 'Hiram of Tyre sent him gifts and workers without being asked', 'The Philistines stopped attacking for three years', 'a', '1 Chronicles 14:2 — "David perceived that the LORD had confirmed him king over Israel, for his kingdom was lifted up on high, because of his people Israel."'),
('1 Chronicles', 14, 'teens', 2, 'What question did David ask the LORD before fighting the Philistines the first time, and what was God''s answer?', 'Shall I go up? God said go up, I will deliver them into thine hand', 'How many men should I take? God said take ten thousand', 'What time should I attack? God said attack at dawn', 'Should I call for reinforcements? God said trust in Me alone', 'a', '1 Chronicles 14:10 — "And David enquired of God, saying, Shall I go up against the Philistines?...And God said unto him, Go up; for I will deliver them into thine hand."'),
('1 Chronicles', 14, 'teens', 3, 'Where did the first great battle against the Philistines in chapter 14 take place?', 'Baal-perazim', 'The valley of Rephaim', 'Pas-dammim', 'The valley of Elah', 'a', '1 Chronicles 14:11 — "So they came up to Baal-perazim; and David smote them there."'),
('1 Chronicles', 14, 'teens', 4, 'What did David name the place of his first victory over the Philistines, and what was the meaning?', 'Baal-perazim, meaning God hath broken in upon mine enemies like the breaking forth of waters', 'Perez-uzza, meaning breach of the enemy', 'Ramath-lehi, meaning the hill of the jawbone', 'En-hakkore, meaning the spring of him who cried', 'a', '1 Chronicles 14:11 — "David said, God hath broken in upon mine enemies by mine hand like the breaking forth of waters: therefore they called the name of that place Baal-perazim."'),
('1 Chronicles', 14, 'teens', 5, 'What different strategy did God command for the second battle with the Philistines compared to the first?', 'David was to go around behind them and come upon them in front of the mulberry trees, not go straight up', 'David was to send his cavalry first and infantry second', 'David was to wait for the Philistines to advance into a narrow valley', 'David was to attack on foot rather than with chariots', 'a', '1 Chronicles 14:14 — "God said unto him, Go not up after them; turn away from them, and come upon them over against the mulberry trees."'),
-- Adults
('1 Chronicles', 14, 'adults', 1, 'How does the Chronicler use the building of David''s house by Hiram to make a theological point about international recognition?', 'It serves as evidence that God confirmed David as king — pagan kings honouring David testifies to divine blessing', 'It introduces the contrast between David''s house and the house (temple) God refused to let him build', 'It shows that Israel''s wealth now exceeded that of the Phoenician merchants', 'It establishes the trade relationship that Solomon will later exploit for temple building', 'a', '1 Chronicles 14:1-2 — Immediately after Hiram''s help, David "perceived that the LORD had confirmed him king over Israel" — the Chronicler places pagan recognition in a theological frame as divine confirmation.'),
('1 Chronicles', 14, 'adults', 2, 'How many sons and daughters are recorded as born to David in Jerusalem, and who are named among them?', 'Thirteen sons are named including Shammua, Shobab, Nathan, and Solomon', 'Six sons and three daughters, all named in the text', 'Ten children, of whom four became kings', 'Eleven sons named, none of whose mothers are identified', 'a', '1 Chronicles 14:4-7 — The text names thirteen sons: "Shammua, and Shobab, Nathan, and Solomon, And Ibhar, and Elishua, and Elpalet, And Nogah, and Nepheg, and Japhia, And Elishama, and Beeliada, and Eliphalet."'),
('1 Chronicles', 14, 'adults', 3, 'Twice before battle David "enquired of God." What does this repeated pattern teach in Chronicles?', 'That seeking God before every action is the defining characteristic of a king who succeeds — the opposite of Saul who did not enquire', 'That God only speaks to kings who have not sinned in the past', 'That the Urim and Thummim must be consulted before every military campaign', 'That prophets must be present at every royal war council', 'a', '1 Chronicles 14:10,14 — David enquired twice; contrast 1 Chronicles 10:14 where "Saul enquired not of the LORD" — this bookending is deliberate Chronicler theology about seeking God as the key to royal success or failure.'),
('1 Chronicles', 14, 'adults', 4, 'What does the command to burn the Philistines'' gods contrast with in the Mosaic law, and what does it show about David?', 'It fulfils Deuteronomy 7:5,25 which commands burning foreign idols — David acts as a second Moses in destroying syncretistic temptations', 'It contrasts with Solomon who tolerated foreign gods in Jerusalem', 'It shows David was more zealous than Moses, who only commanded the idols be smashed', 'It is identical to what Gideon did after defeating the Midianites', 'a', '1 Chronicles 14:12 — "David gave a commandment, and they were burned with fire." Compare Deuteronomy 7:25: "The graven images of their gods shall ye burn with fire." David''s action precisely fulfils Mosaic covenant obligation.'),
('1 Chronicles', 14, 'adults', 5, 'What does the phrase "sound of going in the tops of the mulberry trees" function as in a military theology?', 'It is a divinely-appointed signal — God himself going before the army — making the supernatural the precondition for human advance', 'It is a natural weather phenomenon that creates fog cover for David''s flanking manoeuvre', 'It represents the sound of the Philistine retreat beginning in the far trees', 'It is the sound of the Philistine war chariots circling in the orchards', 'a', '1 Chronicles 14:15 — "When thou shalt hear a sound of going in the tops of the mulberry trees, then thou shalt go out to battle: for God is gone forth before thee to smite the host of the Philistines." God''s prior movement guarantees the victory.'),
('1 Chronicles', 14, 'adults', 6, 'How far did David smite the Philistines in the second battle, according to verse 16?', 'From Gibeon even to Gazer', 'From Jerusalem to the borders of Tyre', 'From the valley of Rephaim to the sea coast', 'From Baal-perazim to the city of Gath', 'a', '1 Chronicles 14:16 — "David smote the host of the Philistines from Gibeon even to Gazer."'),
('1 Chronicles', 14, 'adults', 7, 'What international consequence followed David''s victories over the Philistines?', 'His fame went out into all lands and the LORD brought the fear of him upon all nations', 'All surrounding nations sent tribute and acknowledged his supremacy', 'The Philistines sued for peace and became a vassal state', 'The nations sent ambassadors asking for military alliances', 'a', '1 Chronicles 14:17 — "The fame of David went out into all lands; and the LORD brought the fear of him upon all nations."'),
('1 Chronicles', 14, 'adults', 8, 'How does chapter 14 function structurally as a bridge between the failed first ark-journey (ch. 13) and the successful second one (ch. 15)?', 'It shows David''s growing spiritual maturity — learning to enquire of God — which explains why the second ark attempt succeeds, done according to the proper order', 'It interrupts the ark narrative to introduce David''s family background before he becomes fully established', 'It records David''s military victories that made Jerusalem secure enough to house the ark', 'It explains why Hiram''s craftsmen had to build a special place for the ark in Jerusalem', 'a', '1 Chronicles 14:10,14 — David''s double enquiring of God in chapter 14 contrasts with the un-enquired first ark transport (13:3); having learned to "seek God after the due order" (15:13), David succeeds in chapter 15. The Chronicler arranges the chapters deliberately.');

-- ═══ 1 Chronicles Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 15, 'kids', 1, 'Who did David say must carry the ark of God this time, not the oxen on a cart?', 'The Levites', 'The priests and elders', 'The mighty men and warriors', 'The sons of Aaron alone', 'a', '1 Chronicles 15:2 — "None ought to carry the ark of God but the Levites: for them hath the LORD chosen to carry the ark of God, and to minister unto him for ever."'),
('1 Chronicles', 15, 'kids', 2, 'What did David do as the ark was brought into Jerusalem?', 'He danced before the LORD with all his might', 'He sat on his throne and watched', 'He led the priests in prayer', 'He blew the trumpets himself', 'a', '1 Chronicles 15:29 — "David dancing and playing: and she despised him in her heart." (Compare 1 Chronicles 15:28-29 for the full dancing scene.)'),
('1 Chronicles', 15, 'kids', 3, 'What did Michal, Saul''s daughter, think when she saw David dancing?', 'She despised him in her heart', 'She was filled with joy and praised God', 'She was afraid and hid inside the palace', 'She wept and ran out to join the dancing', 'a', '1 Chronicles 15:29 — "Michal the daughter of Saul looking out at a window saw king David dancing and playing: and she despised him in her heart."'),
-- Teens
('1 Chronicles', 15, 'teens', 1, 'What reason did David give for why God broke out upon them the first time they moved the ark?', 'Because they sought him not after the due order — the Levites had not carried it', 'Because the priests had not offered the required sacrifices beforehand', 'Because David had not prayed and fasted before the journey', 'Because the ark had been in a Gentile''s house and was unclean', 'a', '1 Chronicles 15:13 — "For because ye did it not at the first, the LORD our God made a breach upon us, for that we sought him not after the due order."'),
('1 Chronicles', 15, 'teens', 2, 'What did the Levites do to prepare themselves before carrying the ark the second time?', 'They sanctified themselves', 'They fasted for seven days', 'They immersed themselves in the Jordan River', 'They offered one hundred burnt offerings', 'a', '1 Chronicles 15:14 — "So the priests and the Levites sanctified themselves to bring up the ark of the LORD God of Israel."'),
('1 Chronicles', 15, 'teens', 3, 'How did the Levites carry the ark this time, according to what Moses commanded?', 'Upon their shoulders with the staves of the ark', 'On a gold-covered cart with handles on each side', 'In a covered litter carried by eight men', 'On a wheeled platform pulled by white oxen', 'a', '1 Chronicles 15:15 — "The children of the Levites bare the ark of God upon their shoulders with the staves thereon, as Moses commanded according to the word of the LORD."'),
('1 Chronicles', 15, 'teens', 4, 'Who was appointed as the chief musician over the singing when the ark was brought up?', 'Chenaniah, because he was skilful', 'Asaph with his cymbals', 'Heman son of Joel', 'Obed-edom the Gittite', 'a', '1 Chronicles 15:22 — "Chenaniah, chief of the Levites, was for song: he instructed about the song, because he was skilful."'),
('1 Chronicles', 15, 'teens', 5, 'What musical instruments accompanied the ark''s procession into Jerusalem, as listed in chapter 15?', 'Psalteries, harps, cymbals, and trumpets', 'Flutes, lyres, drums, and cymbals', 'Harps, tambourines, and shofars only', 'Trumpets and timbrels only, as ordained by Moses', 'a', '1 Chronicles 15:28 — "Thus all Israel brought up the ark of the covenant of the LORD with shouting, and with sound of the cornet, and with trumpets, and with cymbals, making a noise with psalteries and harps."'),
-- Adults
('1 Chronicles', 15, 'adults', 1, 'What three Levitical families does David summon, and how many men does each family contribute to carry the ark?', 'Kohath with 120, Merari with 220, Gershom with 130 — plus priests Zadok and Abiathar', 'Kohath with 70, Gershom with 80, Merari with 90 — all sanctified for the task', 'Kohath with 200, Merari with 200, Gershom with 200 — equal portions from each', 'All three families provided forty men each, totalling 120 Levite carriers', 'a', '1 Chronicles 15:7-10 — "Of the sons of Gershom; Joel the chief, and his brethren an hundred and thirty. Of the sons of Merari; Asaiah the chief, and his brethren two hundred and twenty. Of the sons of Uzziel; Amminadab the chief, and his brethren an hundred and twelve."'),
('1 Chronicles', 15, 'adults', 2, 'What does David''s wearing of the linen ephod alongside his royal robe signify theologically?', 'That he assumes a priestly-royal role before the LORD, blurring the distinction in a way that prefigures the Messiah as both king and priest', 'That David was ordained as a Levitical priest by the high priest Zadok', 'That linen was the only fabric permitted near the holy ark', 'That the high priest had given David special authority to lead the ceremony', 'a', '1 Chronicles 15:27 — "David was clothed with a robe of fine linen, and all the Levites that bare the ark...and David had upon him an ephod of linen." The priestly ephod on the king is a typological pointer toward the Melchizedekal priest-king.'),
('1 Chronicles', 15, 'adults', 3, 'How many gatekeepers were appointed for the ark during the procession, and what were their names?', 'Obed-edom and Jehiah, two doorkeepers for the ark', 'Six Levites at the gate and two at the rear', 'Twelve men, one from each tribe, guarding the ark''s path', 'Four priests standing at each corner of the ark', 'a', '1 Chronicles 15:24 — "Obed-edom and Jehiah were doorkeepers for the ark."'),
('1 Chronicles', 15, 'adults', 4, 'What does the sevenfold offering of seven bullocks and seven rams when the Levites bore the ark without incident reveal?', 'That God''s help in carrying the ark without incident prompted immediate costly worship — relief expressed as sacrifice', 'That seven is the covenant number and David was establishing a covenant by the ark''s entry', 'That the law required seven sacrifices at the start of every ark procession', 'That David was fulfilling a vow he had made to God if the Philistines were defeated', 'a', '1 Chronicles 15:26 — "When God helped the Levites that bare the ark of the covenant of the LORD, that they offered seven bullocks and seven rams." Relief, gratitude, and awe motivate immediate worship.'),
('1 Chronicles', 15, 'adults', 5, 'How does the Chronicler expand the musical account of the ark''s arrival compared to 2 Samuel 6?', 'Chronicles gives extensive detail about the Levitical musicians, their instruments, their leaders, and their roles — completely absent in 2 Samuel 6', 'Chronicles shortens the musical description to focus more on David''s prayer', 'Both texts give identical accounts of the musical programme for the procession', 'Chronicles omits the dancing that 2 Samuel records to dignify the worship', 'a', '1 Chronicles 15:16-24 — The nine-verse musical roster (Heman, Asaph, Ethan, psalteries, harps, cymbals, trumpets, and named individuals) is unique to Chronicles; 2 Samuel 6 has no equivalent, reflecting the Chronicler''s deep interest in Levitical music.'),
('1 Chronicles', 15, 'adults', 6, 'Who are Heman, Asaph, and Ethan, and what instruments are assigned to each?', 'All three sounded cymbals of brass; Heman and Asaph and Ethan were principal singers', 'Heman played the harp, Asaph the psaltery, Ethan the trumpet', 'Heman led the choir, Asaph conducted, Ethan composed the psalms', 'Heman played the bass lyre, Asaph the treble lyre, Ethan the timbrel', 'a', '1 Chronicles 15:17,19 — "Heman the son of Joel; and of his brethren, Asaph the son of Berechiah...And Ethan...And Heman, Asaph, and Ethan, were appointed to sound with cymbals of brass."'),
('1 Chronicles', 15, 'adults', 7, 'What specific reason is given for Michal''s contempt for David, and how does her lineage explain the Chronicler''s interest?', 'She was the daughter of Saul — her contempt represents the old dynasty''s rejection of the new order of joyful worship', 'She was offended because David had not invited her to participate in the procession', 'She thought dancing was undignified for a king of Israel and violated royal protocol', 'She was angry that David had married other women while she was given to Phalti', 'a', '1 Chronicles 15:29 — "Michal the daughter of Saul" — the Chronicler identifies her by her father deliberately; her contempt for Davidic worship echoes Saul''s failure to seek God, making her a symbol of the old regime''s spiritual blindness.'),
('1 Chronicles', 15, 'adults', 8, 'What does the contrast between chapters 13 and 15 teach about the relationship between enthusiasm and order in worship?', 'That sincere enthusiasm (ch. 13) without the prescribed means results in tragedy; ordered worship according to God''s revealed will (ch. 15) results in joy and blessing', 'That only professional clergy should ever lead worship, not kings', 'That repetition is necessary before any act of worship can be considered acceptable to God', 'That the more elaborate the preparation, the more pleasing the worship is to God', 'a', '1 Chronicles 15:13 — "We sought him not after the due order." The Chronicler presents the two ark journeys as a deliberate lesson: the first (well-intentioned but wrong-ordered) ends in death; the second (properly ordered) ends in national celebration. Zeal must be channelled through obedience.');

-- ═══ 1 Chronicles Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 16, 'kids', 1, 'What did David give to every Israelite man and woman on the day the ark was placed in the tent?', 'A loaf of bread, a piece of flesh, and a flagon of wine', 'Silver and gold from the treasury', 'A new robe and sandals', 'An animal for sacrifice', 'a', '1 Chronicles 16:3 — "He dealt to every one of Israel, both man and woman, to every one a loaf of bread, and a good piece of flesh, and a flagon of wine."'),
('1 Chronicles', 16, 'kids', 2, 'Who did David appoint to minister before the ark, give thanks, and praise the LORD?', 'Asaph and his brothers', 'Joab and his mighty men', 'The high priest Zadok alone', 'The sons of Aaron in the tabernacle', 'a', '1 Chronicles 16:4-5 — "He appointed certain of the Levites to minister before the ark of the LORD, and to record, and to thank and praise the LORD God of Israel: Asaph the chief."'),
('1 Chronicles', 16, 'kids', 3, 'What did the psalm in chapter 16 say to do when you remember what God has done?', 'Give thanks unto the LORD and call upon his name', 'Fast and pray before the congregation', 'Go to the tabernacle and offer a sacrifice', 'Teach your children all His laws', 'a', '1 Chronicles 16:8 — "Give thanks unto the LORD, call upon his name, make known his deeds among the people."'),
-- Teens
('1 Chronicles', 16, 'teens', 1, 'What psalm did David deliver to Asaph on the day the ark was brought in, as recorded in chapter 16?', 'A psalm of thanksgiving combining verses from Psalms 105, 96, and 106', 'The entire Psalm 23 recited before the congregation', 'A new psalm composed by David on the night before', 'Psalm 100, the traditional psalm of dedication', 'a', '1 Chronicles 16:7-36 — The psalm corresponds to Psalm 105:1-15, Psalm 96:1-13, and Psalm 106:1,47-48, showing how the Chronicler wove together Israel''s hymnody for this occasion.'),
('1 Chronicles', 16, 'teens', 2, 'What does the psalm declare about God''s covenant, and how long it will last?', 'It is the word he commanded to a thousand generations, the covenant he made with Abraham, confirmed to Jacob as an everlasting covenant', 'It is renewed every jubilee year as a sign between God and Israel', 'It lasts as long as the temple stands in Jerusalem', 'It is renewed with each new king from the line of David', 'a', '1 Chronicles 16:15-17 — "Be ye mindful always of his covenant; the word which he commanded to a thousand generations...Which covenant he made with Abraham, and his oath unto Isaac; And confirmed the same to Jacob for a law."'),
('1 Chronicles', 16, 'teens', 3, 'What does the psalm call on all the earth to do in the presence of the LORD?', 'Tremble before him, for he cometh to judge the earth', 'Bring offerings and come before him daily', 'Learn his commandments and teach them to their children', 'Build temples in every nation for his glory', 'a', '1 Chronicles 16:30,33 — "Fear before him, all the earth...Then shall the trees of the wood sing out at the presence of the LORD, because he cometh to judge the earth."'),
('1 Chronicles', 16, 'teens', 4, 'Who was left at the tabernacle in Gibeon to serve there, while Asaph served before the ark in Jerusalem?', 'Zadok the priest and his brethren', 'Abiathar the high priest', 'Obed-edom and his sixty-eight brethren', 'Chenaniah the chief musician', 'a', '1 Chronicles 16:39 — "Zadok the priest, and his brethren the priests, before the tabernacle of the LORD in the high place that was at Gibeon."'),
('1 Chronicles', 16, 'teens', 5, 'What two things does the psalm say are holy and what should those who seek the LORD feel?', 'His name is holy; let the heart of them rejoice that seek the LORD', 'His law is holy; let the obedient be at peace', 'His covenant is holy; let the faithful give double offerings', 'His presence is holy; let the priests tremble before him', 'a', '1 Chronicles 16:10 — "Glory ye in his holy name: let the heart of them rejoice that seek the LORD."'),
-- Adults
('1 Chronicles', 16, 'adults', 1, 'How does the placement of the psalm in chapter 16 serve the Chronicler''s overall theological agenda?', 'It roots the ark''s arrival not merely in political triumph but in covenant theology — Israel''s identity as the people of the LORD''s remembrance and inheritance', 'It introduces David as a composer of psalms to explain why the Psalter later bears his name', 'It provides the liturgical template that Solomon used for the temple dedication', 'It establishes the text that Ezra used when the exiles returned to Jerusalem', 'a', '1 Chronicles 16:8-36 — The psalm proclaims the LORD''s covenant faithfulness across generations and commands remembrance, framing the ark''s return as a covenant renewal event, not merely a political act.'),
('1 Chronicles', 16, 'adults', 2, 'What responsibility was given to Obed-edom the Gittite in his permanent appointment?', 'He was appointed for the ark with sixty-eight brethren, and also for the service of Jeduthun as doorkeeper', 'He was made chief musician in place of Asaph', 'He was appointed treasurer of all the ark''s dedicated offerings', 'He was made the head of the Kohathite division for transport duties', 'a', '1 Chronicles 16:38 — "Obed-edom with their brethren, threescore and eight; Obed-edom also the son of Jeduthun and Hosah to be porters."'),
('1 Chronicles', 16, 'adults', 3, 'What does verse 22 ("Touch not mine anointed, and do my prophets no harm") mean in the context of the psalm''s historical recitation?', 'It refers to God''s protection of the patriarchs as they wandered among pagan nations as a small, vulnerable people', 'It is a command to Israel never to rebuke or correct their king', 'It refers specifically to the protection of the ark from Philistine desecration', 'It is a warning to the nations not to attack the Levitical musicians', 'a', '1 Chronicles 16:20-22 — The psalm recounts God''s protection of Abraham, Isaac, and Jacob as they "went from nation to nation" — "mine anointed" refers to the patriarchs whom God protected as a fragile covenant people.'),
('1 Chronicles', 16, 'adults', 4, 'How does the doxology at the end of the psalm (v. 36) function liturgically, and what does it reveal about Israel''s worship?', 'It calls for the whole assembly''s congregational response — "And all the people said, Amen, and praised the LORD" — showing participatory communal worship', 'It was sung only by the Levites as the priests bowed in silence', 'It was reserved for the Sabbath repeat performance of the psalm', 'It was the signal for the people to begin their individual offerings', 'a', '1 Chronicles 16:36 — "Blessed be the LORD God of Israel for ever and ever. And all the people said, Amen, and praised the LORD." This antiphonal structure mirrors synagogue and temple liturgy.'),
('1 Chronicles', 16, 'adults', 5, 'What does the parallel existence of two worship centres — the ark-tent in Jerusalem and the Mosaic tabernacle in Gibeon — reveal about this transitional period?', 'Israel existed in a liturgically divided state, with old Mosaic forms continuing at Gibeon while the new Davidic worship order was being established at Jerusalem', 'It shows that worship had broken down and needed reform', 'The two centres represented the northern and southern tribes'' separate worship traditions', 'It was a deliberate strategy so that no single location could be attacked and all worship destroyed', 'a', '1 Chronicles 16:37-42 — The Chronicler carefully assigns personnel to both sites, showing continuity with Mosaic worship while simultaneously establishing the new Davidic-Jerusalem worship order that will culminate in Solomon''s temple.'),
('1 Chronicles', 16, 'adults', 6, 'The psalm''s universal scope — calling "all the earth" to praise — has what implication for the Chronicler''s theology of nations?', 'The nations are not merely Israel''s enemies but the intended audience of God''s glory — Israel''s worship is a witness to all peoples', 'The nations will eventually be absorbed into Israel''s political borders under the Messiah', 'Only Israel can properly worship God; the nations are addressed rhetorically, not literally', 'The nations will be judged unless they convert to Judaism within a generation', 'a', '1 Chronicles 16:31 — "Let the heavens be glad, and let the earth rejoice: and let men say among the nations, The LORD reigneth." The universalist vision of the psalm (paralleling Psalm 96) shows that Israel''s covenant worship has a missiological dimension.'),
('1 Chronicles', 16, 'adults', 7, 'What does it mean that Asaph and his brethren were to "minister before the ark continually, as every day''s work required"?', 'That daily, regular, ordered worship was institutionalised as a permanent feature of Israel''s national life under David', 'That the Levites worked around the clock in rotating eight-hour shifts', 'That new psalms were to be composed every day by the appointed musicians', 'That the ark required daily ritual cleansing performed by Asaph''s family', 'a', '1 Chronicles 16:37 — "So he left there before the ark of the covenant of the LORD Asaph and his brethren, to minister before the ark continually, as every day''s work required." Daily worship is the rhythm of covenant life.'),
('1 Chronicles', 16, 'adults', 8, 'How does chapter 16''s detailed worship programme foreshadow the temple worship of 2 Chronicles, and what does this tell us about the Chronicler''s purpose?', 'It establishes the Davidic worship order — music, personnel, daily offerings, praise — as the foundation and model for all subsequent temple worship, showing David as the architect of Israel''s liturgy', 'It is simply a historical record with no intended programmatic significance for later worship', 'It was designed as a corrective response to the worship failures of the wilderness generation', 'It is a polemic against the northern kingdom''s alternative worship centres at Dan and Bethel', 'a', '1 Chronicles 16:4-6,37-42 — The Chronicler''s meticulous attention to Levitical roles, instruments, and daily worship at both centres anticipates the temple establishment in 2 Chronicles 5-7, suggesting his purpose was to legitimise post-exilic Levitical worship by tracing it to David himself.');

-- ═══ 1 Chronicles Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 17, 'kids', 1, 'What did David want to build for God that God told him he would not build?', 'A house (temple) for God', 'A new city for the priests', 'A golden altar for sacrifices', 'A wall around Jerusalem', 'a', '1 Chronicles 17:4 — "Thou shalt not build me an house to dwell in."'),
('1 Chronicles', 17, 'kids', 2, 'Who did God say would build a house for him instead of David?', 'David''s son, who would come after him', 'Solomon''s brother Adonijah', 'The prophet Nathan', 'Joab the army commander', 'a', '1 Chronicles 17:12 — "He shall build me an house, and I will stablish his throne for ever."'),
('1 Chronicles', 17, 'kids', 3, 'In David''s prayer of thanksgiving, what did he call himself before the LORD?', 'Who am I, O LORD God, and what is mine house, that thou hast brought me hitherto?', 'I am thy servant who has kept all thy commandments', 'I am the son of Jesse and the least of the tribe of Judah', 'I am nothing but a shepherd and a warrior before thee', 'a', '1 Chronicles 17:16 — "David the king came and sat before the LORD, and said, Who am I, O LORD God, and what is mine house, that thou hast brought me hitherto?"'),
-- Teens
('1 Chronicles', 17, 'teens', 1, 'What was Nathan''s initial response to David''s desire to build God a house, and why did he have to change it?', 'Nathan first told David to do all that was in his heart, but that night God told Nathan to go back and correct this', 'Nathan refused immediately, saying God had not commanded it', 'Nathan consulted the Urim and Thummim before giving David a negative answer', 'Nathan praised David and began making plans, but David himself changed his mind', 'a', '1 Chronicles 17:2-4 — "Nathan said unto David...Do all that is in thine heart; for God is with thee. And it came to pass the same night, that the word of God came to Nathan, saying, Go and tell David my servant, Thus saith the LORD, Thou shalt not build me an house to dwell in."'),
('1 Chronicles', 17, 'teens', 2, 'What promise did God make about what He would do for David, playing on the word "house"?', 'God said He would build David a house — an everlasting dynasty', 'God promised to protect David''s house from every enemy', 'God said He would name the temple after David''s house', 'God promised that David''s house would never be destroyed', 'a', '1 Chronicles 17:10 — "The LORD will build thee an house." God reverses David''s intention — David wanted to build God a house; God promises to build David a house (dynasty).'),
('1 Chronicles', 17, 'teens', 3, 'What does God promise to do if David''s son commits iniquity, and how does this differ from what happened to Saul?', 'He will chasten him with the rod of men but will not take his mercy away as he took it from Saul', 'He will remove his son from the throne and give the kingdom to another tribe', 'He will send a plague on Israel as punishment for the king''s sin', 'He will correct him through prophets but never allow him to be removed from office', 'a', '1 Chronicles 17:13 — "I will be his father, and he shall be my son: and I will not take my mercy away from him, as I took it from him that was before thee."'),
('1 Chronicles', 17, 'teens', 4, 'According to the Davidic covenant in chapter 17, what will be the permanent status of Israel once God has planted them?', 'They shall dwell in a place of their own and shall be moved no more, neither shall the children of wickedness waste them any more', 'They shall become the greatest nation on earth within three generations', 'They shall inherit all the land from the Nile to the Euphrates', 'They shall never go into captivity again as long as they keep the law', 'a', '1 Chronicles 17:9 — "I will appoint a place for my people Israel, and will plant them, and they shall dwell in their place, and shall be removed no more; neither shall the children of wickedness waste them any more."'),
('1 Chronicles', 17, 'teens', 5, 'What does David say there is none like in all the earth, based on what they have heard with their ears?', 'There is none like thee, O LORD, neither is there any God beside thee', 'There is no nation like Israel whom God redeemed from Egypt', 'There is no king like David in all the generations of Israel', 'There is no city like Jerusalem among all the cities of the world', 'a', '1 Chronicles 17:20 — "O LORD, there is none like thee, neither is there any God beside thee, according to all that we have heard with our ears."'),
-- Adults
('1 Chronicles', 17, 'adults', 1, 'How does the wordplay on "house" (bayit) structure God''s response to David in chapter 17?', 'David wants to build God a house/temple; God turns it around — I will build YOU a house/dynasty — the greater gift is dynastic permanence, not a building', 'The wordplay contrasts the tent-house God has always used with the permanent house Israel needs', 'God rebukes the idea of a house because houses are for the dead and God is the living God', 'The reversal shows that David''s house must first be purified before any temple can be built', 'a', '1 Chronicles 17:4,10 — "Thou shalt not build me an house...the LORD will build thee an house." The Hebrew bayit (house) means both building and dynasty; God''s response elevates David''s request into an eternal covenant gift.'),
('1 Chronicles', 17, 'adults', 2, 'What historical argument does God use to show he never needed a house, and what does this reveal about divine transcendence?', 'God says he has gone from tent to tent and from one tabernacle to another and never asked any judge to build him a cedar house', 'God argues that the Egyptians had temples but he destroyed them, showing temples invite syncretism', 'God points to Abraham who worshipped without a temple and was called God''s friend', 'God reminds David that the manna and the pillar of fire required no building to house them', 'a', '1 Chronicles 17:5-6 — "For I have not dwelt in an house since the day that I brought up Israel unto this day; but have gone from tent to tent, and from one tabernacle to another...have I spoken a word...to build me an house of cedar?"'),
('1 Chronicles', 17, 'adults', 3, 'What is the theological significance of God saying "I took thee from the sheepcote" to David?', 'It establishes the humility of David''s origins as the theological ground of God''s grace — the dynasty rests entirely on divine election, not human merit', 'It explains why David''s psalms use shepherd imagery so frequently', 'It is a reminder to David that God can remove him as easily as he was raised', 'It distinguishes David from Saul who came from a noble family of Benjaminite warriors', 'a', '1 Chronicles 17:7 — "I took thee from the sheepcote, even from following the sheep, that thou shouldest be ruler over my people Israel." Election from lowly origins is a key Chronicler motif, paralleling Moses and Joseph.'),
('1 Chronicles', 17, 'adults', 4, 'How does the Davidic covenant in 1 Chronicles 17 differ from the version in 2 Samuel 7, and what does the omission reveal about the Chronicler''s purpose?', 'Chronicles omits any mention of chastening David''s heir with the rod of men (2 Sam 7:14b), presenting a more purely unconditional, idealized covenant, possibly for post-exilic hope', 'Chronicles adds extensive details about the temple''s dimensions that are absent in 2 Samuel 7', 'Chronicles places the covenant before the ark''s arrival, while 2 Samuel 7 places it after', 'Chronicles gives Nathan''s oracle in David''s own words rather than as a prophetic speech', 'a', '2 Samuel 7:14 includes "I will chasten him with the rod of men" which is softened in 1 Chronicles 17:13 — "I will not take my mercy away from him" — the Chronicler''s post-exilic audience needed assurance that the Davidic hope remained alive despite the exile''s discipline.'),
('1 Chronicles', 17, 'adults', 5, 'What does David''s prayer in response to the Davidic covenant reveal about his understanding of grace versus merit?', 'He confesses utter unworthiness — "Who am I...?" — acknowledging that everything is gift, not reward, and that God''s greatness alone explains his favour', 'He promises to obey all God''s commands as the condition for the covenant''s fulfilment', 'He asks God to explain exactly what conditions he must meet to keep the dynasty secure', 'He thanks God but immediately begins planning the temple to reciprocate God''s generosity', 'a', '1 Chronicles 17:16-18 — "Who am I, O LORD God...thou hast also spoken of thy servant''s house for a great while to come, and hast regarded me according to the estate of a man of high degree, O LORD God." David''s response is pure doxology, not bargaining.'),
('1 Chronicles', 17, 'adults', 6, 'How does verse 14 — "I will settle him in mine house and in my kingdom for ever" — differ from the parallel in 2 Samuel 7:16?', 'In 2 Samuel 7:16 God says "thine house and thy kingdom"; in 1 Chronicles 17:14 God says "mine house and my kingdom" — emphasising that the kingdom belongs ultimately to God, not to the Davidic line', 'In 2 Samuel the covenant is with all Israel; in Chronicles it is with David''s line alone', 'The verse is identical in both texts with no meaningful variation', 'Chronicles adds a time limit of one thousand years that 2 Samuel does not contain', 'a', '1 Chronicles 17:14 — "I will settle him in mine house and in my kingdom for ever: and his throne shall be established for evermore." The subtle shift from "thine" to "mine" is theologically significant — the Chronicler subordinates the Davidic kingdom to divine sovereignty.'),
('1 Chronicles', 17, 'adults', 7, 'What does David''s prayer contribute to the Chronicler''s portrait of ideal kingship?', 'The ideal king is one who sits in God''s presence in humble prayer, acknowledging divine sovereignty and interceding for the people, not merely winning battles', 'The ideal king is one who builds temples and institutes correct worship forms', 'The ideal king is one who defeats all enemies before turning to spiritual matters', 'The ideal king is one who delegates worship to the Levites and focuses on governance', 'a', '1 Chronicles 17:16-27 — David''s twelve-verse prayer of humble adoration is the Chronicler''s portrait of a king wholly yielded to God, contrasting with Saul''s self-reliance; the prayer prefigures Solomon''s dedication prayer in 2 Chronicles 6.'),
('1 Chronicles', 17, 'adults', 8, 'How does the Davidic covenant of chapter 17 serve as the theological spine of the entire Books of Chronicles?', 'All subsequent Chronicles narrative — Solomon''s temple, the kings'' evaluations, the exile, and the postscript of Cyrus — is measured against the covenant''s promise of an eternal throne, creating both a narrative of failure and an eschatological hope', 'It serves only as a historical record of one evening''s encounter between a king and a prophet', 'It establishes the legal framework for priestly succession in the post-exilic community', 'It functions as a polemic against the northern kingdom''s claim to covenant succession', 'a', '1 Chronicles 17:14 — "His throne shall be established for evermore." The whole of Chronicles can be read as a meditation on this promise — will it be fulfilled? Kings fail, the temple burns, exile comes, yet Cyrus''s decree (2 Chron 36:23) points forward to ultimate fulfilment beyond the text.');

-- ═══ 1 Chronicles Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 18, 'kids', 1, 'What people did David defeat and subdue, taking Gath and its towns?', 'The Philistines', 'The Ammonites', 'The Syrians', 'The Edomites', 'a', '1 Chronicles 18:1 — "David smote the Philistines, and subdued them, and took Gath and her towns out of the hand of the Philistines."'),
('1 Chronicles', 18, 'kids', 2, 'What did David do with the gold, silver, and bronze he captured from the nations he conquered?', 'He dedicated them to the LORD', 'He gave them to his soldiers as reward', 'He hid them underground for safekeeping', 'He traded them with Hiram of Tyre', 'a', '1 Chronicles 18:11 — "Them also king David dedicated unto the LORD, with the silver and gold that he brought from all these nations."'),
('1 Chronicles', 18, 'kids', 3, 'Who was put in charge of David''s army?', 'Joab son of Zeruiah', 'Abishai son of Zeruiah', 'Benaiah son of Jehoiada', 'Adino the Eznite', 'a', '1 Chronicles 18:15 — "Joab the son of Zeruiah was over the host."'),
-- Teens
('1 Chronicles', 18, 'teens', 1, 'What did Tou king of Hamath send to David, and why?', 'He sent his son Hadoram with gold, silver, and brass to congratulate David for defeating Hadarezer', 'He sent tribute of grain and oil as a sign of submission', 'He sent soldiers to help David fight the Ammonites', 'He sent a letter requesting a peace treaty between their kingdoms', 'a', '1 Chronicles 18:10 — "He sent Hadoram his son to king David, to enquire of his welfare, and to congratulate him, because he had fought against Hadarezer...for Hadarezer had war with Tou."'),
('1 Chronicles', 18, 'teens', 2, 'What was the scale of David''s victory over the Syrians of Damascus?', 'He put garrisons in Syria of Damascus; the Syrians became David''s servants and brought gifts', 'He destroyed the city of Damascus and scattered its population', 'He took the Syrian king captive to Jerusalem', 'He burned the Syrian cities and returned to Jerusalem with twenty thousand slaves', 'a', '1 Chronicles 18:6 — "David put garrisons in Syria-damascus; and the Syrians became David''s servants, and brought gifts. Thus the LORD preserved David whithersoever he went."'),
('1 Chronicles', 18, 'teens', 3, 'How many Syrian horsemen and foot soldiers did David kill at the battle with Hadarezer king of Zobah?', 'A thousand chariots, seven thousand horsemen, and twenty thousand footmen', 'Five hundred chariots and three thousand horsemen', 'Two thousand chariots and ten thousand horsemen', 'Three hundred chariots and seven thousand cavalry', 'a', '1 Chronicles 18:4 — "David took from him a thousand chariots, and seven thousand horsemen, and twenty thousand footmen."'),
('1 Chronicles', 18, 'teens', 4, 'What did David do with the horses from Hadarezer''s captured chariots?', 'He houghed (hamstrung) all the chariot horses and kept only a hundred', 'He gave them to Joab for his cavalry units', 'He sent them to Hiram of Tyre as tribute', 'He sacrificed them at the tabernacle in Gibeon', 'a', '1 Chronicles 18:4 — "David houghed all the chariot horses, but reserved of them an hundred chariots."'),
('1 Chronicles', 18, 'teens', 5, 'Who served as David''s priest and who served as his scribe among his principal officers?', 'Zadok son of Ahitub and Abimelech son of Abiathar were priests; Shavsha was scribe', 'Abiathar was the only priest and Joab served also as scribe', 'Ahimaaz was priest and Seraiah was scribe', 'Eleazar was the chief priest and Jonathan his son was scribe', 'a', '1 Chronicles 18:16 — "Zadok the son of Ahitub, and Abimelech the son of Abiathar, were the priests; and Shavsha was scribe."'),
-- Adults
('1 Chronicles', 18, 'adults', 1, 'What repeated refrain in chapter 18 explains the theological reason for David''s military success?', '"The LORD preserved David whithersoever he went" — divine protection, not human strategy, is the stated cause', '"David was mighty in battle because God had anointed him"', '"The fear of the LORD fell on all the nations round about"', '"David sought the LORD before every battle and was never defeated"', 'a', '1 Chronicles 18:6,13 — Both verses end with the identical phrase: "the LORD preserved David whithersoever he went," bracketing the chapter''s military accounts with a consistent theological interpretation.'),
('1 Chronicles', 18, 'adults', 2, 'What territory did David place garrisons in after defeating Edom in the valley of salt, and how many Edomites died?', 'He put garrisons throughout all Edom after David''s servants smote 18,000 Edomites in the valley of salt', 'He occupied the city of Petra and stationed one thousand men there', 'He garrisoned the Jordan fords and the roads to Egypt', 'He placed garrisons only in the port of Elath on the Red Sea', 'a', '1 Chronicles 18:12-13 — "Abishai the son of Zeruiah slew of the Edomites in the valley of salt eighteen thousand. And he put garrisons in Edom; and all the Edomites became David''s servants."'),
('1 Chronicles', 18, 'adults', 3, 'How does the list of David''s officers in verses 15-17 compare to the parallel list in 2 Samuel 8:16-18, specifically regarding David''s sons?', '2 Samuel says David''s sons were chief rulers (priests); 1 Chronicles says they were chief about the king — the Chronicler softens the priestly title for non-Levitical sons', 'Both texts are identical in every detail about David''s sons and their roles', 'Chronicles promotes David''s sons to priestly rank while 2 Samuel omits them entirely', 'The Chronicler replaces David''s sons with Levites to avoid the appearance of royal priestly overreach', 'a', '2 Samuel 8:18 calls David''s sons "priests" (kohanim); 1 Chronicles 18:17 calls them "chief about the king" — the Chronicler carefully avoids attributing priestly status to non-Levitical sons of David, consistent with his strict Levitical theology.'),
('1 Chronicles', 18, 'adults', 4, 'What does the detail that David dedicated war spoils "for the building of the house of God" contribute to the narrative?', 'It shows David''s entire military career as providentially funding the temple — even his wars serve the worship agenda', 'It explains why David had enough wealth to purchase the threshing floor at full price', 'It contrasts with Solomon who had to levy heavy taxes to build the temple', 'It proves David had already designed the temple before Nathan''s oracle', 'a', '1 Chronicles 18:8,11 — The bronze from Tibhath and Chun and the dedicated silver and gold point forward to 1 Chronicles 22:14-16 where David explicitly says he has prepared iron, bronze, silver, and gold for the house of God.'),
('1 Chronicles', 18, 'adults', 5, 'David hamstrung the chariot horses keeping only a hundred — how does this fulfil Mosaic law regarding kings?', 'Deuteronomy 17:16 forbids the king from multiplying horses; David''s houghing demonstrates obedience to the royal law', 'Numbers 31 commanded all enemy animals to be destroyed, and David partially complied', 'Leviticus 27 forbade offering horses and David destroyed them rather than leave them unconsecrated', 'There is no specific Mosaic law about horses; the houghing was purely practical', 'a', '1 Chronicles 18:4 — "David houghed all the chariot horses." Deuteronomy 17:16: "He shall not multiply horses to himself." David''s action intentionally limits his military-industrial power in covenant obedience, unlike Solomon who multiplied horses (1 Kings 10:26).'),
('1 Chronicles', 18, 'adults', 6, 'How does chapter 18''s summary of David''s reign — "David reigned over all Israel, and executed judgment and justice among all his people" — function as a theological evaluation?', 'It is the Chronicler''s ideal royal formula — justice (mishpat) and righteousness (tsedaqah) are the covenant markers of legitimate kingship, echoing the prophetic ideal', 'It is a purely administrative summary with no evaluative theological content', 'It contrasts with Saul who reigned but did not execute justice', 'It introduces the transition to Solomon whose reign of peace exceeded David''s reign of war', 'a', '1 Chronicles 18:14 — "David reigned over all Israel, and executed judgment and justice among all his people." Compare Psalm 72:1-2 and Jeremiah 22:3 — justice and judgment are the twin pillars of covenantal kingship throughout the Hebrew Bible.'),
('1 Chronicles', 18, 'adults', 7, 'Who was Benaiah son of Jehoiada over, and what does his role suggest about David''s security apparatus?', 'He was over the Cherethites and Pelethites — likely foreign mercenary bodyguards forming the royal guard', 'He commanded the Levitical temple guard which David established for the ark''s protection', 'He was the general of the reserve army that never left Jerusalem', 'He was in charge of the intelligence service and diplomatic correspondence', 'a', '1 Chronicles 18:17 — "Benaiah the son of Jehoiada was over the Cherethites and the Pelethites." The Cherethites and Pelethites are widely understood as professional Aegean-origin mercenaries serving as David''s personal bodyguard, distinct from the tribal military forces.'),
('1 Chronicles', 18, 'adults', 8, 'What does the Chronicler''s organisation of chapters 18-20 (a block of David''s wars) between the Davidic covenant (ch. 17) and the temple preparations (ch. 21-29) suggest about his theological narrative strategy?', 'The wars are presented as the providential means by which God prepares the wealth, peace, and security necessary for the temple — war serves the temple agenda', 'The wars represent a digression from the main spiritual narrative of David''s relationship with God', 'The placement shows that David''s military success disqualified him from building the temple', 'The Chronicler organised the wars chronologically, with no further theological significance', 'a', 'The structural logic of Chronicles places military victories (chs. 18-20) between the covenant promise of an eternal house (ch. 17) and the actual temple preparations (chs. 21-29), showing that the wars are not incidental but are the God-orchestrated means of assembling the resources and conditions for the central act of the Davidic era: preparing for the temple.');

-- ═══ 1 Chronicles Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 19, 'kids', 1, 'Why did David send men to the new Ammonite king Hanun?', 'To show kindness because Hanun''s father Nahash had shown kindness to David', 'To demand tribute from the new king', 'To warn Hanun not to attack Israel''s borders', 'To ask Hanun for soldiers to fight the Philistines', 'a', '1 Chronicles 19:2 — "David said, I will shew kindness unto Hanun the son of Nahash, because his father shewed kindness to me."'),
('1 Chronicles', 19, 'kids', 2, 'What rude thing did King Hanun do to David''s servants?', 'He shaved off half their beards and cut their garments in the middle', 'He threw them in prison for a month', 'He made them carry heavy stones through the city', 'He painted their faces and sent them back as a joke', 'a', '1 Chronicles 19:4 — "Hanun took David''s servants, and shaved them, and cut off their garments in the middle, even to their buttocks, and sent them away."'),
('1 Chronicles', 19, 'kids', 3, 'Who helped the Ammonites fight against Israel by sending thousands of soldiers?', 'The Syrians', 'The Philistines', 'The Moabites', 'The Edomites', 'a', '1 Chronicles 19:6-7 — "The children of Ammon sent a thousand talents of silver to hire them chariots and horsemen out of Mesopotamia, and out of Syria-maachah, and out of Zobah."'),
-- Teens
('1 Chronicles', 19, 'teens', 1, 'Why were David''s servants shamed and what kindness did David show them before they returned to Jerusalem?', 'The Ammonites said they were spies; David told them to stay in Jericho until their beards grew back', 'David sent new robes and escorted them home in secrecy', 'David publicly honoured them in Jerusalem to restore their dignity', 'David avenged their shame immediately by attacking Rabbah that same night', 'a', '1 Chronicles 19:3-5 — The Ammonite princes said the men were spies. David said "Tarry at Jericho until your beards be grown, and then return."'),
('1 Chronicles', 19, 'teens', 2, 'How did Joab divide his forces to fight both the Ammonites and the Syrians at the same time?', 'He chose the best soldiers against the Syrians himself and gave the rest to Abishai his brother against the Ammonites', 'He sent Benaiah against the Syrians and kept the main force against the Ammonites', 'He divided into three groups: one for the gates, one for the field, and one in reserve', 'He retreated to a strong position and let the enemies fight each other first', 'a', '1 Chronicles 19:11 — "The rest of the people he delivered into the hand of Abishai his brother, and they set themselves in array against the children of Ammon."'),
('1 Chronicles', 19, 'teens', 3, 'What was the mutual support agreement Joab and Abishai made before the battle?', 'If the Syrians were too strong for Joab, Abishai would help him, and vice versa against the Ammonites', 'They agreed that whoever won first would pursue the enemy as far as Damascus', 'They promised to combine their forces if either side lost more than half their men', 'They agreed to retreat together if the Ammonites brought reinforcements from the south', 'a', '1 Chronicles 19:12 — "If the Syrians be too strong for me, then thou shalt help me: but if the children of Ammon be too strong for thee, then I will help thee."'),
('1 Chronicles', 19, 'teens', 4, 'After the Syrians fled from Joab, what did the Ammonites do?', 'They also fled before Abishai and entered the city', 'They surrendered and asked for terms of peace', 'They retreated to Rabbah and prepared for a long siege', 'They called for more reinforcements from beyond the Euphrates', 'a', '1 Chronicles 19:15 — "When the children of Ammon saw that the Syrians were fled, they likewise fled before Abishai his brother, and entered into the city."'),
('1 Chronicles', 19, 'teens', 5, 'After their defeat, Hadarezer rallied the Syrians from beyond the river. What happened when David personally led Israel against them?', 'David smote the Syrians; seven thousand men of the Syrians in chariots and forty thousand footmen died, and the Syrian kings became his servants', 'The Syrians retreated without fighting and sued for peace', 'The battle was indecisive and ended in a treaty dividing the land', 'David''s general Joab won the battle while David remained in Jerusalem', 'a', '1 Chronicles 19:18 — "David slew of the Syrians seven thousand men which fought in chariots, and forty thousand footmen, and killed Shophach the captain of the host."'),
-- Adults
('1 Chronicles', 19, 'adults', 1, 'What does the Ammonite misreading of David''s diplomatic mission reveal about the theological danger of suspicion and dishonour?', 'Treating kindness as espionage is the primal sin of dishonour that breaks covenant relationships and launches unnecessary wars — the Ammonite princes project their own treachery onto David''s good faith', 'It shows that international diplomacy was always inherently dangerous in the ancient Near East', 'It demonstrates that David''s diplomatic ventures were not wise given the hostile regional climate', 'It reveals that the Ammonites had a legitimate reason to distrust Israel based on past history', 'a', '1 Chronicles 19:3 — "The princes of the children of Ammon said to Hanun, Thinkest thou that David doth honour thy father, that he hath sent comforters unto thee? are not his servants come unto thee for to search?" Suspicion of grace is the seed of catastrophic conflict.'),
('1 Chronicles', 19, 'adults', 2, 'The Ammonites hired thirty-two thousand chariots plus the kings of Maachah and Tob. What does this display of force indicate about the broader geopolitical stakes of the conflict?', 'The Ammonites recognised that their insult of David''s ambassadors had made war inevitable and assembled a pan-Aramean coalition — this was an existential military conflict, not a border skirmish', 'It shows that the Ammonites were wealthier than Israel and could afford any military force', 'It demonstrates that surrounding nations were eager to limit David''s expanding empire', 'It proves that the Ammonites had been planning this war long before the insult occurred', 'a', '1 Chronicles 19:7 — "They hired thirty and two thousand chariots, and the king of Maachah and his people" — a massive coalition army assembled against David, showing the gravity of the confrontation.'),
('1 Chronicles', 19, 'adults', 3, 'What does Joab''s speech to his troops before battle reveal about Chronicler theology of warfare?', 'Joab commends the cause and outcome to the LORD — "let the LORD do that which is good in his sight" — subordinating military strategy to divine providence', 'Joab gives a nationalist speech about Israel''s superiority to all surrounding nations', 'Joab quotes the Mosaic law about holy war and calls for dedication of all spoils to the sanctuary', 'Joab promises the soldiers a double share of plunder if they fight without fear', 'a', '1 Chronicles 19:13 — "Be of good courage, and let us behave ourselves valiantly for our people, and for the cities of our God: and let the LORD do that which is good in his sight." The outcome is surrendered to God''s sovereign will.'),
('1 Chronicles', 19, 'adults', 4, 'How does the phrase "cities of our God" (v. 13) function theologically in Joab''s pre-battle speech?', 'It frames the military campaign as defence of God''s own property and covenant inheritance — not mere national interest but sacred obligation', 'It is a conventional ancient Near Eastern phrase meaning simply the homeland', 'It refers specifically to the sanctuary cities designated as Levitical cities under Joshua', 'It establishes that all cities in Israel had equal sacred status before God', 'a', '1 Chronicles 19:13 — "For our people, and for the cities of our God" — the possessive "of our God" theologises the territory as divine patrimony, making its defence an act of covenant faithfulness.'),
('1 Chronicles', 19, 'adults', 5, 'How does this chapter''s account compare to 2 Samuel 10 in terms of narrative emphasis and what does the difference show?', 'Both texts are closely parallel but Chronicles omits 2 Samuel 11''s David and Bathsheba episode which follows — the Chronicler presents David''s wars without the moral failure that 2 Samuel embeds within them', 'Chronicles gives more military detail while 2 Samuel focuses on the diplomacy', 'Chronicles records the battle outcomes differently, with higher casualty figures throughout', 'Chronicles includes Nathan''s rebuke of David at the end of the Ammonite war which 2 Samuel omits', 'a', '1 Chronicles 19 || 2 Samuel 10: The Chronicler follows 2 Samuel 10 closely but deliberately skips 2 Samuel 11-12 (Bathsheba, Uriah''s murder, Nathan''s rebuke) — the Chronicler''s portrait of David is consistently idealized, focusing on his role as temple-preparer rather than moral failure.'),
('1 Chronicles', 19, 'adults', 6, 'What is the significance of the Syrians'' decision to make peace with David and serve him after their defeat?', 'It fulfills the Abrahamic promise that nations would serve Israel, and echoes 1 Chronicles 14:17 that nations feared David — each victory expands the shadow of the coming Davidic-Messianic kingdom', 'It eliminated the Syrian threat permanently, allowing David to focus on internal administration', 'It was the diplomatic outcome David had originally sought through his ambassadors', 'It created a buffer zone between Israel and the larger empires of Mesopotamia', 'a', '1 Chronicles 19:19 — "The servants of Hadarezer saw that they were put to the worse before Israel, they made peace with David, and became his servants." Compare Genesis 12:3 — the nations'' submission to the Davidic heir of Abraham is a covenant-fulfilment pattern.'),
('1 Chronicles', 19, 'adults', 7, 'What does the killing of Shophach the Syrian commander accomplish narratively?', 'It decapitates the Syrian military leadership, removing the strategic threat and making the subsequent Ammonite campaign (ch. 20) a manageable mopping-up operation', 'It fulfils a prophetic word that God would give David victory over all the northern nations', 'It demonstrates Joab''s military genius in targeting enemy command structures', 'It establishes David''s moral claim to all Syrian territory north of Damascus', 'a', '1 Chronicles 19:18 — "David...killed Shophach the captain of the host." Shophach''s death mirrors Sisera''s death in Judges — the captain killed signals the army''s collapse and the war''s resolution.'),
('1 Chronicles', 19, 'adults', 8, 'How does the escalation from a diplomatic insult (v. 4) to a pan-regional war (vv. 16-19) serve the Chronicler''s portrait of David as a universal sovereign?', 'Each escalation — local Ammonites, hired Arameans, then trans-Euphrates Syrians — is defeated, progressively expanding David''s sphere of dominion and demonstrating that no human coalition can thwart God''s anointed', 'The escalation is presented as a cautionary tale about the dangers of military over-confidence', 'It shows the limits of David''s empire since he never crossed the Euphrates himself', 'The escalation serves only to justify the large tribute that the conquered nations later paid to Solomon', 'a', '1 Chronicles 19:16-19 — The expanding circle of enemies from Ammon to local Syria to trans-Euphrates Syria, all defeated in sequence, mirrors the Chronicler''s schema of David subduing "all the nations" (18:11) as the promised Davidic sovereign whose kingdom will have no borders.');

-- ═══ 1 Chronicles Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 20, 'kids', 1, 'What great city of the Ammonites did Joab defeat, and what did David do with its king''s crown?', 'He conquered Rabbah and put the king''s crown on David''s own head', 'He burned Rabbah and gave the crown to the high priest', 'He destroyed Rabbah and threw the crown into the Jordan River', 'He captured Rabbah and put the crown in the temple treasury', 'a', '1 Chronicles 20:2 — "David took the crown of their king from off his head, and found it to weigh a talent of gold, and there were precious stones in it; and it was set upon David''s head."'),
('1 Chronicles', 20, 'kids', 2, 'What giant did Sibbechai the Hushathite kill in a battle against the Philistines?', 'Sippai, one of the sons of the giant', 'Goliath''s brother Lahmi', 'The giant from Gath with six fingers on each hand', 'Ishbi-benob who had a spear weighing three hundred shekels', 'a', '1 Chronicles 20:4 — "Sibbechai the Hushathite slew Sippai, that was of the children of the giant."'),
('1 Chronicles', 20, 'kids', 3, 'Who killed the giant at Gath who had twenty-four fingers and toes?', 'Jonathan the son of Shimea, David''s brother', 'Elhanan the son of Jair', 'Abishai the son of Zeruiah', 'Benaiah the son of Jehoiada', 'a', '1 Chronicles 20:6-7 — "There was yet a man of great stature, whose fingers and toes were four and twenty, six on each hand, and six on each foot: and he also was the son of the giant. But Jonathan the son of Shimea David''s brother slew him."'),
-- Teens
('1 Chronicles', 20, 'teens', 1, 'At what time of year did kings go out to battle, and what did Joab do while David stayed in Jerusalem?', 'In the spring when kings went forth to battle; Joab led the army and smote Rabbah while David tarried at Jerusalem', 'In the autumn harvest season; Joab guarded Jerusalem while David led the army abroad', 'In the winter dry season; Joab besieged Rabbah while David inspected the northern tribes', 'In the summer heat; Joab recruited new soldiers while David reorganised the kingdom''s defences', 'a', '1 Chronicles 20:1 — "At the time that kings go out to battle, Joab led forth the power of the army, and wasted the country of the children of Ammon, and came and besieged Rabbah. But David tarried at Jerusalem."'),
('1 Chronicles', 20, 'teens', 2, 'How heavy was the crown taken from the Ammonite king''s head that was placed on David''s head?', 'A talent of gold with precious stones in it', 'Two hundred shekels of gold', 'Half a talent of silver and gold combined', 'Three hundred shekels of pure gold', 'a', '1 Chronicles 20:2 — "David took the crown of their king from off his head, and found it to weigh a talent of gold, and there were precious stones in it; and it was set upon David''s head."'),
('1 Chronicles', 20, 'teens', 3, 'What happened to the people of the Ammonite cities after Rabbah was conquered?', 'David brought out the people and set them to work with saws, harrows, axes, and brought them to Israel', 'David killed all the soldiers and set the civilians free', 'David took the Ammonite leaders captive and made the rest pay tribute', 'David expelled all the Ammonites from the region and settled Israelites in their place', 'a', '1 Chronicles 20:3 — "He brought out the people that were in it, and cut them with saws, and with harrows of iron, and with axes."'),
('1 Chronicles', 20, 'teens', 4, 'Who was Lahmi and who killed him?', 'He was the brother of Goliath the Gittite, slain by Elhanan the son of Jair', 'He was a Philistine giant killed by Abishai son of Zeruiah', 'He was the son of Sippai, killed by Sibbechai the Hushathite', 'He was a Syrian giant who challenged Israel at the Jordan', 'a', '1 Chronicles 20:5 — "Elhanan the son of Jair slew Lahmi the brother of Goliath the Gittite, whose spear staff was like a weaver''s beam."'),
('1 Chronicles', 20, 'teens', 5, 'How many battles with Philistine giants does chapter 20 record in total, and what is the summary statement about them?', 'Three battles; these were born unto the giant in Gath and fell by the hand of David and by the hand of his servants', 'Two battles; both giants were killed by men from the tribe of Judah', 'Four battles; the last giant surrendered and became a vassal of David', 'Three battles; all three giants were killed by members of David''s bodyguard personally', 'a', '1 Chronicles 20:8 — "These were born unto the giant in Gath; and they fell by the hand of David, and by the hand of his servants."'),
-- Adults
('1 Chronicles', 20, 'adults', 1, 'What is the theological and narrative significance of the Chronicler opening chapter 20 with "David tarried at Jerusalem" without the Bathsheba episode that follows in 2 Samuel 11?', 'The Chronicler deliberately omits David''s greatest moral failure to preserve the idealised portrait of David as the divinely-commissioned temple-preparer, whose legacy must remain untainted for post-exilic readers', 'The Chronicler simply did not have access to the Bathsheba source used by the Samuel author', 'The Chronicler omits it because it is covered in full detail in the book of Psalms', 'The Chronicler omits it because it occurred after his narrative cut-off point', 'a', '1 Chronicles 20:1 parallels 2 Samuel 11:1 word-for-word in the opening clause, then diverges sharply — the Chronicler knew the Bathsheba tradition but chose not to record it, a theological decision about what defines David''s legacy.'),
('1 Chronicles', 20, 'adults', 2, 'How does the crown scene at Rabbah function symbolically in the Davidic narrative?', 'The enemy king''s crown transferred to David''s head is a visible symbol of legitimate universal sovereignty — the nations'' crowns belong to God''s anointed king', 'It is a practical detail showing David compensated himself for the cost of the war', 'It is a deliberate act of humiliation designed to demoralise the Ammonite survivors', 'It establishes the legal claim that David''s successors had over Ammonite territory', 'a', '1 Chronicles 20:2 — The crown transfer echoes the symbolism of Psalm 2:8 — "Ask of me, and I shall give thee the heathen for thine inheritance." The anointed king receiving the nations'' crowns is a coronation theology moment.'),
('1 Chronicles', 20, 'adults', 3, 'What is the apparent textual difficulty in comparing 2 Samuel 21:19 with 1 Chronicles 20:5 regarding Goliath''s killer?', '2 Samuel 21:19 says Elhanan killed Goliath himself; 1 Chronicles 20:5 says he killed Lahmi the brother of Goliath — Chronicles resolves the apparent contradiction by specifying it was Goliath''s brother', 'The texts agree completely and there is no apparent difficulty', '2 Samuel gives the correct name while 1 Chronicles has a scribal error', 'The two texts refer to two different men named Elhanan fighting two different battles', 'a', '1 Chronicles 20:5 — "Elhanan the son of Jair slew Lahmi the brother of Goliath" versus 2 Samuel 21:19 — "Elhanan...slew the brother of Goliath" (with some manuscripts reading differently). The 1 Chronicles text appears to clarify a scribal compression in Samuel.'),
('1 Chronicles', 20, 'adults', 4, 'What does the phrase "sons of the giant" (rephaim) suggest about the Philistine giant warriors of Gath?', 'It connects them to the pre-Israelite Rephaim/Anakim warrior tradition, linking these battles to the unfinished conquest of Canaan that Israel finally completes under David', 'It simply means they were very tall men descended from an unusually large family', 'It connects them to the Nephilim of Genesis 6 and implies demonic origin', 'It is a military title given to the elite warrior caste of the Philistine army', 'a', '1 Chronicles 20:4,6,8 — "Sons of the giant" (yalid ha-rapha) connects to the Anakim/Rephaim whom the spies feared (Numbers 13:33) and Caleb conquered (Joshua 15:14) — David''s warriors complete the conquest these earlier generations could not finish.'),
('1 Chronicles', 20, 'adults', 5, 'What does the six-fingered, six-toed giant of Gath contribute to the Chronicler''s portrait of David''s era?', 'The extraordinary nature of the enemies David''s servants overcome demonstrates that the Davidic era is one of supernatural divine empowerment — ordinary men defeating extraordinary foes', 'It is a medical curiosity recorded for ethnographic completeness', 'It proves that the Philistines practised selective breeding to produce warrior giants', 'It establishes a genealogical record for the Gittite families who survived into the post-exilic period', 'a', '1 Chronicles 20:6-7 — "There was yet a man of great stature, whose fingers and toes were four and twenty...Jonathan the son of Shimea David''s brother slew him." The hyperbolic physicality of the enemy magnifies the victory''s significance.'),
('1 Chronicles', 20, 'adults', 6, 'How does the conquest of Rabbah complete the narrative arc begun in chapter 19, and what does it show about delayed divine justice?', 'Hanun''s contemptuous insult of David''s ambassadors (ch. 19) is finally answered with the utter conquest of his royal city and the subjugation of his people — divine justice works through historical process, not instant retribution', 'It shows that military campaigns in the ancient world always took years to complete', 'It demonstrates that Joab was a more capable general than David in siege warfare', 'It proves that the Ammonites could not have been conquered without Syrian assistance being neutralised first', 'a', '1 Chronicles 19:3-4 establishes the Ammonite contempt; 1 Chronicles 20:1-3 records the consequence — the very city from which Hanun ruled is conquered and its people subjugated. The narrative arc demonstrates that no dishonour of God''s anointed goes unanswered.'),
('1 Chronicles', 20, 'adults', 7, 'The chapter ends with the summary "these were born unto the giant in Gath, and they fell by the hand of David and by the hand of his servants." What does this closing formula achieve?', 'It collectivises the victories — David''s servants share in his royal triumph, prefiguring the Messianic king whose people participate in his victories', 'It protects David''s personal reputation by acknowledging he did not fight every giant himself', 'It functions as a legal record establishing each warrior''s claim to land grants for their service', 'It is a formulaic closing phrase with no deeper theological significance', 'a', '1 Chronicles 20:8 — "They fell by the hand of David, and by the hand of his servants." The conjunction is significant: the king''s victory is shared with his servants, a pattern of participatory kingship that later New Testament theology applies to the Messianic king and his people.'),
('1 Chronicles', 20, 'adults', 8, 'How does chapters 18-20 as a unit (David''s wars) prepare the reader for the temple-preparation section that begins in chapter 21?', 'The wars establish the geographical and military security, the material wealth from spoils, and the demonstration of divine favour that together make the temple project both possible and theologically warranted — peace requires prior warfare', 'The wars section is structurally separate from the temple section and has no direct connection to it', 'The wars section ends David''s career as a warrior so the reader can see him transition naturally to a builder role', 'The wars establish the boundary lines of the land that the temple will be built to consecrate', 'a', '1 Chronicles 18:8,11 — The bronze from Tibhath and dedicated spoils from all nations explicitly point to temple use; 1 Chronicles 22:14 confirms David prepared these materials for the house of God. The war chapters are therefore integral to the temple-preparation narrative, not a parenthesis.');
